#include<stdio.h>
int main()
{
    int a,n,i;
    scanf("%d",&n);

    for (i=0;i<n;i++)
    {
      scanf("%d",&a);
      while(a >= 3 && a % 7 != 0)
        a -= 3;
      if(a == 0 || a % 7 == 0)
         printf("YES\n");
      else
          printf("NO\n");
    }
}

