use std::io::Write;

fn run() {
    let out = std::io::stdout();
    let mut out = std::io::BufWriter::new(out.lock());
    input! {
        n: usize,
        x: [u32; n],
    }
    for x in x {
        let mut ans = "NO";
        for a in 0..=100 {
            for b in 0..=100 {
                if 3 * a + 7 * b == x {
                    ans = "YES";
                }
            }
        }
        writeln!(out, "{}", ans).ok();
    }
}

fn main() {
    run();
}
